INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 61, 'kids', 1, 'Where did David ask God to lead him when his heart was overwhelmed?', 'To a high rock', 'To a river', 'To a cave', 'To a mountain', 'a', 'David prayed, "Lead me to the rock that is higher than I" (Psalm 61:2).'),
('Psalms', 61, 'kids', 2, 'What did David want to do in God''s tabernacle forever?', 'Sing songs', 'Abide there', 'Offer sacrifices', 'Read scrolls', 'b', 'David said, "I will abide in thy tabernacle for ever" (Psalm 61:4).'),
('Psalms', 61, 'kids', 3, 'What did David say he would do daily in the psalm?', 'Pray alone', 'Perform his vows', 'Fast and weep', 'Sleep in peace', 'b', 'David said, "So will I sing praise unto thy name for ever, that I may daily perform my vows" (Psalm 61:8).'),
('Psalms', 61, 'teens', 1, 'From where did David cry unto God in Psalm 61?', 'From the temple', 'From the end of the earth', 'From the wilderness', 'From the city of David', 'b', 'David cried, "From the end of the earth will I cry unto thee, when my heart is overwhelmed" (Psalm 61:2).'),
('Psalms', 61, 'teens', 2, 'What two things did David say God had been to him?', 'A refuge and a tower', 'A shield and a sword', 'A lamp and a path', 'A rock and a river', 'a', 'David said God had been "a shelter for me, and a strong tower from the enemy" (Psalm 61:3).'),
('Psalms', 61, 'teens', 3, 'What did David say he trusted in regarding the king in Psalm 61?', 'That the king would conquer all enemies', 'That God would prolong the king''s life', 'That the king would build a great temple', 'That the king would defeat David''s enemies', 'b', 'David prayed that God would prolong the king''s life and that "his years as many generations" (Psalm 61:6).'),
('Psalms', 61, 'teens', 4, 'What two things did David ask to be sent to preserve the king?', 'Angels and fire', 'Mercy and truth', 'Wisdom and strength', 'Rain and sunshine', 'b', 'David prayed, "O prepare mercy and truth, which may preserve him" (Psalm 61:7).'),
('Psalms', 61, 'teens', 5, 'What musical term heads Psalm 61, indicating it was to be used with what instrument?', 'A harp', 'A neginah (stringed instrument)', 'A flute', 'Cymbals', 'b', 'Psalm 61 is headed "To the chief Musician upon Neginah" — a stringed instrument (Psalm 61 superscription).'),
('Psalms', 61, 'adults', 1, 'What Hebrew word rendered "overwhelmed" in Psalm 61:2 conveys the sense of fainting or being covered over?', 'Atap', 'Ataph', 'Nephesh', 'Shachah', 'b', 'The word "ataph" (overwhelmed) in Psalm 61:2 means to be faint, covered, or feeble — David feels utterly spent.'),
('Psalms', 61, 'adults', 2, 'What does David''s phrase "the rock that is higher than I" theologially convey?', 'God is taller than mountains', 'God''s salvation is beyond David''s own ability to reach it', 'David wanted to climb a literal rock', 'God''s throne is above all creation', 'b', 'The phrase "lead me to the rock that is higher than I" (Psalm 61:2) expresses that God''s help transcends human ability.'),
('Psalms', 61, 'adults', 3, 'What does David''s desire to "abide in thy tabernacle for ever" (Psalm 61:4) reflect about his deepest longing?', 'A wish for priestly office', 'An unbroken dwelling in God''s presence as the highest good', 'A desire to live in Jerusalem', 'A vow to never leave the city', 'b', 'David''s longing to abide in God''s tabernacle forever (Psalm 61:4) reflects that God''s presence is his supreme joy.'),
('Psalms', 61, 'adults', 4, 'The phrase "under the shadow of thy wings" in Psalm 61:4 is a recurring OT image. What does it primarily symbolize?', 'God''s power in battle', 'Divine protection and sheltering care', 'The wings of cherubim on the ark', 'The eagle imagery of Deuteronomy', 'b', 'The shadow of God''s wings (Psalm 61:4) is a tender image of divine shelter and protection, used also in Psalm 17:8 and 91:4.'),
('Psalms', 61, 'adults', 5, 'How does Psalm 61:6-7 function as a Messianic or royal prayer?', 'It prophesies the birth of a king in Bethlehem', 'It intercedes for the ideal king whose reign is perpetual, ultimately fulfilled in Christ', 'It describes David''s own coronation', 'It predicts the return of Solomon', 'b', 'The prayer for the king''s endless life and mercy (Psalm 61:6-7) points beyond any earthly king to the eternal reign of Christ.'),
('Psalms', 61, 'adults', 6, 'What vow does David make at the close of Psalm 61?', 'To offer a thousand burnt offerings', 'To daily perform his vows and sing praise to God''s name forever', 'To never leave Jerusalem', 'To build a house for God', 'b', 'David concludes, "So will I sing praise unto thy name for ever, that I may daily perform my vows" (Psalm 61:8).'),
('Psalms', 61, 'adults', 7, 'What attribute of God is emphasized by the pairing of "mercy and truth" in Psalm 61:7?', 'God''s power and holiness', 'God''s covenant faithfulness and reliable love', 'God''s omniscience and justice', 'God''s creativity and wisdom', 'b', 'Mercy (hesed — covenant love) and truth (emet — faithfulness) together describe God''s reliable covenant character (Psalm 61:7).'),
('Psalms', 61, 'adults', 8, 'What does the heading "upon Neginah" suggest about the original liturgical use of Psalm 61?', 'It was sung a cappella', 'It was performed with a single stringed instrument, likely the lute or lyre', 'It was a whispered prayer', 'It was chanted by a choir', 'b', 'Neginah refers to a stringed instrument; the psalm was composed for musical accompaniment in Israel''s worship (Psalm 61 superscription).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 62, 'kids', 1, 'What did David say his soul did toward God in Psalm 62?', 'It sang loudly', 'It waited silently', 'It ran quickly', 'It cried out', 'b', 'David said, "My soul waiteth upon God: from him cometh my salvation" (Psalm 62:1).'),
('Psalms', 62, 'kids', 2, 'What did David call God in Psalm 62 — his rock and his what?', 'His sword', 'His salvation', 'His king', 'His shepherd', 'b', 'David called God "my rock and my salvation" (Psalm 62:2).'),
('Psalms', 62, 'kids', 3, 'Who does Psalm 62 say power belongs to?', 'The king', 'God', 'The army', 'The angels', 'b', 'David declared, "Power belongeth unto God" (Psalm 62:11).'),
('Psalms', 62, 'teens', 1, 'How does David describe trusting in men of low and high degree in Psalm 62?', 'They are trustworthy if chosen by God', 'They are altogether vanity and lighter than a breath', 'They are good helpers in times of need', 'They can be trusted if they are righteous', 'b', 'David wrote that men of low and high degree are "altogether vanity... lighter than vanity" (Psalm 62:9).'),
('Psalms', 62, 'teens', 2, 'What did David say not to trust in, specifically mentioning robbery?', 'Weapons and armies', 'Oppression and robbery — and riches that increase', 'The wisdom of counsellors', 'The strength of kings', 'b', 'David warned, "Trust not in oppression, and become not vain in robbery: if riches increase, set not your heart upon them" (Psalm 62:10).'),
('Psalms', 62, 'teens', 3, 'How many times does the phrase "only" (or "only he") appear as a refrain in Psalm 62, emphasizing exclusive trust in God?', 'Once', 'Three times', 'Five times', 'Seven times', 'b', 'The word "only" (Hebrew: ak) appears as a refrain in Psalm 62:1, 2, 4, 5, 6 — about three key refrains stressing sole dependence on God.'),
('Psalms', 62, 'teens', 4, 'To what does David compare his enemies'' assault on him in Psalm 62:3?', 'A flood sweeping him away', 'A leaning wall and a tottering fence', 'A lion ready to devour', 'A fire burning around him', 'b', 'David asks, "How long will ye imagine mischief against a man? ye shall be slain all of you: as a bowing wall shall ye be, and as a tottering fence" (Psalm 62:3).'),
('Psalms', 62, 'teens', 5, 'What two things does David say God renders to every man in Psalm 62:12?', 'Life and death', 'Mercy and salvation according to his work', 'Wisdom and power', 'Riches and honour', 'b', 'David wrote, "Also unto thee, O Lord, belongeth mercy: for thou renderest to every man according to his work" (Psalm 62:12).'),
('Psalms', 62, 'adults', 1, 'What Hebrew term is translated "truly" or "only" (ak) and serves as the structural refrain of Psalm 62, appearing in verses 1, 2, 4, 5, and 6?', 'Selah', 'Ak', 'Higgaion', 'Maskil', 'b', 'The particle ak (only/surely/truly) anchors each stanza of Psalm 62, directing the reader''s sole trust to God.'),
('Psalms', 62, 'adults', 2, 'What does "my soul waiteth upon God" (Psalm 62:1) — the Hebrew "dummiyyah" — literally mean?', 'Active petition', 'Silent rest or stillness before God', 'Loud praise', 'Patient endurance in suffering', 'b', 'Dummiyyah means silence or stillness; "my soul waiteth in silence upon God" (Psalm 62:1) speaks of calm, wordless trust.'),
('Psalms', 62, 'adults', 3, 'What does David''s metaphor of God as a "rock" and "fortress" (Psalm 62:2, 6-7) emphasize?', 'God''s physical size', 'God''s immovable stability and protection in contrast to flimsy human support', 'The temple''s stone construction', 'The mountains of Israel', 'b', 'The rock and fortress imagery (Psalm 62:2, 6-7) contrasts God''s absolute stability with the vanity of human help.'),
('Psalms', 62, 'adults', 4, 'How does Psalm 62:9 use a balance/scale image to make its point about humanity?', 'It says the righteous outweigh the wicked', 'It says all men laid in a balance are lighter than vanity', 'It says God weighs human hearts', 'It says riches weigh down the soul', 'b', 'Psalm 62:9 says men of low and high degree "laid in the balance...are altogether lighter than vanity."'),
('Psalms', 62, 'adults', 5, 'What do the two attributes named in Psalm 62:11-12 — "power" and "mercy" — reveal about God''s character?', 'That God is both distant and near', 'That God''s omnipotence is exercised through covenant love, not arbitrary force', 'That God rewards the powerful with mercy', 'That power and mercy compete in God', 'b', 'Psalm 62:11-12 pairs God''s power with mercy, showing his might is always governed by his covenant love.'),
('Psalms', 62, 'adults', 6, 'What does "God hath spoken once; twice have I heard this" (Psalm 62:11) illustrate as a literary device?', 'God spoke audibly twice to David', 'A numerical graduation device (x, x+1) emphasizing the certainty of what was said', 'David had two prophetic dreams', 'God repeats himself for emphasis only', 'b', 'The "once...twice" formula (Psalm 62:11) is a Hebrew literary device (cf. Proverbs 6:16) stressing the absolute certainty of the truth.'),
('Psalms', 62, 'adults', 7, 'What does David mean by "pour out your heart before him" (Psalm 62:8)?', 'Make a blood offering', 'Express every burden, emotion, and need openly to God in prayer', 'Weep publicly in the temple', 'Confess sins to the priest', 'b', 'Pouring out the heart before God (Psalm 62:8) is an image of complete, uninhibited self-disclosure in prayer (cf. 1 Samuel 1:15).'),
('Psalms', 62, 'adults', 8, 'How does Jeduthun''s name in the heading of Psalm 62 connect to Israel''s worship structure?', 'Jeduthun was a king of Israel', 'Jeduthun was one of David''s three chief musicians appointed for temple worship', 'Jeduthun was a scribe who collected psalms', 'Jeduthun was a prophet who interpreted psalms', 'b', 'Jeduthun (1 Chronicles 16:41-42) was one of David''s three chief worship leaders; Psalm 62 was committed to his care for Israel''s liturgy.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 63, 'kids', 1, 'Where was David when he wrote Psalm 63?', 'In a palace', 'In the wilderness of Judah', 'By a river', 'In a cave by the sea', 'b', 'The superscription reads, "A Psalm of David, when he was in the wilderness of Judah" (Psalm 63 superscription).'),
('Psalms', 63, 'kids', 2, 'What did David say his soul did for God like a thirsty body?', 'Thirsted for him', 'Slept peacefully', 'Danced for joy', 'Sang all night', 'a', 'David said, "My soul thirsteth for thee, my flesh longeth for thee in a dry and thirsty land" (Psalm 63:1).'),
('Psalms', 63, 'kids', 3, 'What did David say he would do while lying on his bed at night?', 'Count the stars', 'Remember God and meditate on him', 'Pray for his enemies', 'Sing out loud', 'b', 'David said, "When I remember thee upon my bed, and meditate on thee in the night watches" (Psalm 63:6).'),
('Psalms', 63, 'teens', 1, 'What does David say is better than life in Psalm 63:3?', 'God''s presence in the temple', 'God''s lovingkindness', 'A righteous kingdom', 'The joy of praise', 'b', 'David declared, "Because thy lovingkindness is better than life, my lips shall praise thee" (Psalm 63:3).'),
('Psalms', 63, 'teens', 2, 'How does David describe his praise — what posture does he mention?', 'Bowing low to the ground', 'Lifting up his hands in God''s name', 'Dancing in a circle', 'Kneeling at the altar', 'b', 'David wrote, "Thus will I bless thee while I live: I will lift up my hands in thy name" (Psalm 63:4).'),
('Psalms', 63, 'teens', 3, 'What image does David use to describe his soul''s satisfaction in God?', 'A spring of living water', 'Marrow and fatness', 'Honey from the comb', 'Bread from heaven', 'b', 'David said, "My soul shall be satisfied as with marrow and fatness; and my mouth shall praise thee with joyful lips" (Psalm 63:5).'),
('Psalms', 63, 'teens', 4, 'What does David say about those who seek his soul to destroy it?', 'They will be forgiven', 'They will go into the lower parts of the earth and fall by the sword', 'They will be scattered like chaff', 'They will be turned back in shame', 'b', 'David said his enemies "shall go into the lower parts of the earth... they shall fall by the sword" (Psalm 63:9-10).'),
('Psalms', 63, 'teens', 5, 'What does David call himself in Psalm 63:1 — using what divine title for God?', 'My Shepherd', 'O God, thou art my God', 'My King and my God', 'My Rock and Fortress', 'b', 'David opens with "O God, thou art my God; early will I seek thee" (Psalm 63:1).'),
('Psalms', 63, 'adults', 1, 'What does the Hebrew word "shachar" (translated "early will I seek thee" in Psalm 63:1) literally convey?', 'Seeking at noon', 'Diligently seeking at dawn, implying earnest and urgent pursuit', 'Searching in darkness', 'Seeking with the whole congregation', 'b', 'Shachar means to seek at dawn or diligently; "early will I seek thee" (Psalm 63:1) conveys urgent, first-priority devotion.'),
('Psalms', 63, 'adults', 2, 'What is the theological weight of David''s assertion that lovingkindness is "better than life" (Psalm 63:3)?', 'David preferred death to life without God', 'God''s covenant love (hesed) surpasses physical existence as the highest good', 'Life in the wilderness was miserable', 'David was suicidal and longed for heaven', 'b', 'To declare lovingkindness better than life (Psalm 63:3) places God''s hesed above the most precious earthly possession — life itself.'),
('Psalms', 63, 'adults', 3, 'The phrase "in the shadow of thy wings" (Psalm 63:7) echoes what broader OT theological theme?', 'The wings of seraphim in Isaiah', 'God''s maternal sheltering of his people (cf. Deuteronomy 32:11; Ruth 2:12; Psalm 91:4)', 'The eagle as a symbol of Israel''s military power', 'The wings of the cherubim on the mercy seat', 'b', 'The shadow of God''s wings (Psalm 63:7) is a recurring image of tender divine protection, rooted in Deuteronomy 32:11 and Boaz''s blessing in Ruth 2:12.'),
('Psalms', 63, 'adults', 4, 'How does David''s night meditation (Psalm 63:6) reflect ancient Near Eastern spiritual practice?', 'Night was considered the time of evil spirits', 'The night watches were times of prayer and contemplation in Israel''s worship calendar', 'David could not sleep due to enemies', 'Night was set aside for fasting not prayer', 'b', 'Night watches were established periods of prayer and guard (cf. Psalm 119:148); David''s night meditation (Psalm 63:6) shows his constant communion with God.'),
('Psalms', 63, 'adults', 5, 'What does David''s description of his soul clinging to God — "my soul followeth hard after thee" (Psalm 63:8) — convey in Hebrew (dabaq)?', 'A passive waiting for God', 'An intense, tenacious cleaving to God like a marriage bond (cf. Genesis 2:24)', 'A desperate search in confusion', 'A ritual act of sacrifice', 'b', 'Dabaq (cleave/cling) in Psalm 63:8 is the same word used in Genesis 2:24 for a husband cleaving to his wife — total covenant attachment.'),
('Psalms', 63, 'adults', 6, 'What does the fate of David''s enemies — their mouths stopped (Psalm 63:11) — contrast with in the psalm''s structure?', 'The silence of the wilderness', 'David''s own lips praising and swearing by God, contrasted with lying mouths stopped', 'The silence of night meditation', 'The king''s wordless reign', 'b', 'The stopped mouths of liars (Psalm 63:11) contrast pointedly with David''s praising lips (Psalm 63:3, 5) — praise silences wickedness.'),
('Psalms', 63, 'adults', 7, 'What military or royal context likely underlies Psalm 63''s composition in the wilderness?', 'David''s flight from Saul in the Judean desert', 'David''s flight from Absalom''s rebellion when he crossed the wilderness east of Jerusalem', 'David''s forty years of wandering', 'David''s campaign against the Philistines', 'b', 'The superscription and David''s reference to "the king" (Psalm 63:11) suggest this was written during Absalom''s rebellion, when David fled across the Judean wilderness.'),
('Psalms', 63, 'adults', 8, 'Psalm 63:3 has been called one of the boldest statements in the Psalter. What makes it theologically radical?', 'It claims God is visible in the wilderness', 'It elevates divine love above physical life, reversing the natural hierarchy of values', 'It denies the value of temple worship', 'It asserts that martyrdom is the highest good', 'b', 'By placing lovingkindness above life itself (Psalm 63:3), David subordinates the most prized earthly good to God''s covenantal love — a radical reordering of values.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 64, 'kids', 1, 'What did David ask God to preserve him from in Psalm 64?', 'Rain and storms', 'Fear of the enemy', 'Wild animals', 'Disease and sickness', 'b', 'David prayed, "Preserve my life from fear of the enemy" (Psalm 64:1).'),
('Psalms', 64, 'kids', 2, 'What did David say God would shoot at the wicked?', 'A stone', 'An arrow', 'A bolt of lightning', 'A spear', 'b', 'David declared, "God shall shoot at them with an arrow; suddenly shall they be wounded" (Psalm 64:7).'),
('Psalms', 64, 'kids', 3, 'What would all men do when they saw God''s judgment on the wicked?', 'They would be afraid and declare God''s work', 'They would run away', 'They would laugh', 'They would weep', 'a', 'David said all men "shall fear, and shall declare the work of God; for they shall wisely consider of his doing" (Psalm 64:9).'),
('Psalms', 64, 'teens', 1, 'How does David describe the secret plotting of the wicked in Psalm 64?', 'They plot openly in the city gates', 'They shoot in secret at the blameless man with bitter words as arrows', 'They gather armies against the righteous', 'They bribe judges against the innocent', 'b', 'David said they "shoot in secret at the perfect: suddenly do they shoot at him, and fear not" (Psalm 64:4).'),
('Psalms', 64, 'teens', 2, 'What do the wicked say about their evil plots in Psalm 64:5?', 'God will judge us', 'Who shall see them?', 'We will not be caught', 'No man can stop us', 'b', 'The wicked encouraged themselves and said, "Who shall see them?" (Psalm 64:5).'),
('Psalms', 64, 'teens', 3, 'What body part of the wicked does David say will cause their downfall?', 'Their hands', 'Their tongue', 'Their feet', 'Their eyes', 'b', 'David said, "So they shall make their own tongue to fall upon themselves" (Psalm 64:8).'),
('Psalms', 64, 'teens', 4, 'What does David say the righteous will do in response to God''s judgment in Psalm 64:10?', 'They will rejoice in the LORD and trust in him', 'They will weep for the wicked', 'They will build altars of thanksgiving', 'They will tell all nations', 'a', 'David wrote, "The righteous shall be glad in the LORD, and shall trust in him; and all the upright in heart shall glory" (Psalm 64:10).'),
('Psalms', 64, 'teens', 5, 'What does David compare the enemy''s sharp and bitter words to in Psalm 64:3?', 'A sharp sword and bitter poison', 'Their tongue like a sword and their words like arrows', 'A bitter root and a sharp thorn', 'A whip and a spear', 'b', 'David said the enemies "whet their tongue like a sword, and bend their bows to shoot their arrows, even bitter words" (Psalm 64:3).'),
('Psalms', 64, 'adults', 1, 'What literary device dominates Psalm 64, and how does it create a reversal between the wicked and the righteous?', 'Chiasm — the structure mirrors itself perfectly', 'Poetic justice — the weapons (arrows/words) the wicked use against David are turned against them by God', 'Acrostic — each verse begins with a Hebrew letter', 'Anaphora — the same opening phrase repeats', 'b', 'The poetic justice of Psalm 64 is that God shoots the wicked with an arrow (64:7), reversing their secret shooting of arrows (bitter words) at the righteous (64:3-4).'),
('Psalms', 64, 'adults', 2, 'What does David''s request to be hidden from the "secret counsel of the wicked" (Psalm 64:2) imply about the threat he faces?', 'Open warfare by known enemies', 'An organized conspiracy of hidden enemies plotting his destruction', 'A foreign invasion', 'A legal dispute before judges', 'b', 'The "secret counsel" and "insurrection of workers of iniquity" (Psalm 64:2) describe a covert conspiracy — likely David''s political enemies.'),
('Psalms', 64, 'adults', 3, 'What is the theological principle illustrated when "their own tongue" causes the wicked to fall (Psalm 64:8)?', 'Sin is always found out by witnesses', 'God uses the very instruments of wickedness as instruments of judgment — self-defeating sin', 'Speech is the most powerful human weapon', 'God punishes the wicked by silencing them', 'b', 'When their own tongue falls upon themselves (Psalm 64:8), the psalm illustrates how sin carries within itself the seeds of its own destruction.'),
('Psalms', 64, 'adults', 4, 'What does the phrase "they commune of laying snares privily" (Psalm 64:5) reveal about the psychology of the wicked?', 'They are cowards who fear open confrontation', 'They encourage one another in secret scheming, mistakenly believing they are hidden from God', 'They work alone and do not collaborate', 'They are ignorant of moral law', 'b', 'Psalm 64:5 exposes the self-deception of the wicked: they commune secretly and ask "who shall see them?" — forgetting God''s omniscience.'),
('Psalms', 64, 'adults', 5, 'What does "they search out iniquities; they accomplish a diligent search" (Psalm 64:6) emphasize?', 'The wicked are thorough investigators', 'The wicked apply painstaking effort and ingenuity to sin — wickedness is their industry', 'God searches out the iniquities of the wicked', 'The righteous investigate wrongdoing', 'b', 'Psalm 64:6 ironically credits the wicked with great diligence — "they accomplish a diligent search" — showing that sin is a deliberate, effortful enterprise.'),
('Psalms', 64, 'adults', 6, 'How does "suddenly shall they be wounded" (Psalm 64:7) contrast with the plotting tempo earlier in the psalm?', 'It shows God is slow to anger', 'The wicked''s careful, prolonged scheming is answered by God''s instantaneous decisive judgment', 'The wicked wound suddenly so God wounds slowly', 'It shows judgment comes in stages', 'b', 'The wicked plot carefully and patiently (Psalm 64:2-6), but God''s arrow strikes suddenly (Psalm 64:7) — divine judgment comes without warning at the appointed moment.'),
('Psalms', 64, 'adults', 7, 'What is the communal effect described in Psalm 64:9 when all men see God''s judgment?', 'National mourning for the wicked', 'A universal fear of God and declaration of his works — a witness to the nations', 'A political revolution', 'A revival only among the righteous', 'b', 'When all men fear and declare God''s work (Psalm 64:9), God''s judgment on the wicked becomes a universal testimony to his power and justice.'),
('Psalms', 64, 'adults', 8, 'What does Psalm 64''s movement from personal lament to universal praise (verse 10) model for believers?', 'That prayers are always answered quickly', 'That individual trust in God''s justice leads to corporate rejoicing — personal faith has communal dimensions', 'That the righteous must wait passively', 'That praise replaces the need for prayer', 'b', 'Psalm 64 moves from David''s personal plea (64:1-2) to universal praise (64:9-10), modeling how faith in God''s justice becomes shared worship.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 65, 'kids', 1, 'What did the psalmist say God crowns the year with in Psalm 65?', 'Rain and floods', 'His goodness', 'Gold and silver', 'Flowers and fruit', 'b', 'The psalmist declared, "Thou crownest the year with thy goodness" (Psalm 65:11).'),
('Psalms', 65, 'kids', 2, 'Where does God dwell and receive praise according to Psalm 65:1?', 'In the wilderness', 'In Zion', 'In the heavens', 'In the sea', 'b', 'The psalmist says, "Praise waiteth for thee, O God, in Sion" (Psalm 65:1).'),
('Psalms', 65, 'kids', 3, 'What did God do to the seas and waves to show his power in Psalm 65?', 'He dried them up', 'He stilled the noise of them', 'He turned them to rivers', 'He raised them to the mountains', 'b', 'The psalmist said God "stilleth the noise of the seas, the noise of their waves" (Psalm 65:7).'),
('Psalms', 65, 'teens', 1, 'What does Psalm 65:2 say that allows all flesh to come to God?', 'His great power', 'He hears prayer', 'His righteousness', 'His mercy alone', 'b', 'The psalmist said, "O thou that hearest prayer, unto thee shall all flesh come" (Psalm 65:2).'),
('Psalms', 65, 'teens', 2, 'What does God do with the transgressions of his people according to Psalm 65:3?', 'He records them all', 'He purges them away', 'He punishes them severely', 'He remembers them no more', 'b', 'The psalmist wrote, "As for our transgressions, thou shalt purge them away" (Psalm 65:3).'),
('Psalms', 65, 'teens', 3, 'What blessing is given to the one whom God chooses and causes to approach him in Psalm 65:4?', 'Long life and many children', 'Satisfaction with the goodness of God''s house and holy temple', 'Wealth and honour', 'Victory over all enemies', 'b', 'The psalmist wrote, "Blessed is the man whom thou choosest... that he may dwell in thy courts: we shall be satisfied with the goodness of thy house" (Psalm 65:4).'),
('Psalms', 65, 'teens', 4, 'What does Psalm 65 say God does to establish the mountains, showing his great power?', 'He speaks and they appear', 'He is girded with strength and sets fast the mountains', 'He lifts them from the sea', 'He causes them to tremble and bow', 'b', 'The psalmist declared, "Which by his strength setteth fast the mountains; being girded with power" (Psalm 65:6).'),
('Psalms', 65, 'teens', 5, 'How does Psalm 65 describe the tracks of God''s chariot — what drops from them?', 'Manna and dew', 'Fatness', 'Fire and lightning', 'Rain and grain', 'b', 'The psalmist wrote, "Thy paths drop fatness" (Psalm 65:11), describing God''s providential abundance.'),
('Psalms', 65, 'adults', 1, 'What does "praise waiteth for thee" (Psalm 65:1) mean in the Hebrew, where the verb is related to "silence" (dumiyyah)?', 'Praise is offered in loud song', 'Praise is quietly expectant — a still, reverent waiting before God that is itself a form of worship', 'Praise has been postponed until later', 'Praise is offered only by the priests', 'b', 'The Hebrew dumiyyah suggests silent, expectant praise (Psalm 65:1) — adoration that is calm and awestruck before God''s greatness.'),
('Psalms', 65, 'adults', 2, 'What is the theological significance of "unto thee shall all flesh come" (Psalm 65:2) in the context of this psalm?', 'It predicts the physical resurrection of all people', 'It indicates that God''s hearing of prayer is universally available — no nation is excluded from approaching him', 'It refers only to Israel''s pilgrimage feasts', 'It means all flesh will be judged', 'b', 'The universal scope of "all flesh" (Psalm 65:2) anticipates the Gentile inclusion in the NT — all peoples may approach God through prayer.'),
('Psalms', 65, 'adults', 3, 'How does Psalm 65:3 balance human sinfulness with divine grace?', 'It denies that the people have sinned', 'It acknowledges that iniquities prevail against us, yet God purges transgressions — grace overwhelms sin', 'It teaches that sin is unavoidable and unpunishable', 'It promises that obedient people will never sin', 'b', 'Psalm 65:3 is honest: "iniquities prevail against me," yet God purges them — a frank acknowledgment of human sin met by divine atoning grace.'),
('Psalms', 65, 'adults', 4, 'What does "thou that art the confidence of all the ends of the earth, and of them that are afar off upon the sea" (Psalm 65:5) reveal about the scope of God''s salvation?', 'God''s power is limited to Israel and its borders', 'God is the hope and security of all nations and peoples everywhere — a universalist missional vision', 'The sea represents chaos that God must restrain', 'The ends of the earth are unreachable by prayer', 'b', 'Psalm 65:5 declares God is the confidence of all earth''s ends — a remarkable missional statement that anticipates the gospel reaching every nation.'),
('Psalms', 65, 'adults', 5, 'What does the agricultural imagery of Psalm 65:9-13 (watering the earth, softening it, blessing the grain, crowning the year) theologically affirm?', 'Israel must perform rain rituals to ensure harvest', 'God is the sovereign provider of all natural blessing — creation itself is sustained by his personal care', 'The harvest is a reward for Israel''s obedience only', 'Nature operates independently of God', 'b', 'The rich agricultural imagery of Psalm 65:9-13 affirms that God personally visits and waters the earth — all creation depends on his providential care.'),
('Psalms', 65, 'adults', 6, 'What does "the river of God, which is full of water" (Psalm 65:9) represent in the context of this psalm?', 'The literal Jordan River', 'The heavenly supply of rain — God''s provision channel for the earth''s fertility', 'A river in the garden of Eden', 'The waters above the firmament', 'b', 'The river of God full of water (Psalm 65:9) is a poetic image of God''s heavenly reservoir of rain that he uses to water and bless the earth.'),
('Psalms', 65, 'adults', 7, 'How does Psalm 65 move structurally from the personal/communal to the cosmic?', 'It begins with creation and ends with personal prayer', 'It moves from personal forgiveness and temple access (65:1-4) through God''s cosmic power (65:5-8) to universal agricultural blessing (65:9-13)', 'It moves from farming to temple worship', 'The structure is random and does not progress', 'b', 'Psalm 65 is structured in three movements: personal salvation (65:1-4), cosmic power (65:5-8), and providential provision in nature (65:9-13).'),
('Psalms', 65, 'adults', 8, 'What does the psalmist mean that the valleys "shout for joy, they also sing" (Psalm 65:13)?', 'Literally, the grain fields make audible sounds', 'Nature itself joins creation''s praise — all of creation is personified as a worshipping community', 'The people in the valleys sing harvest songs', 'Angels sing in the valleys', 'b', 'The singing valleys (Psalm 65:13) personify creation as a worshipping community, anticipating Romans 8:19-22 where creation waits for redemption.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 66, 'kids', 1, 'What does Psalm 66 tell all the earth to make unto God?', 'A large offering', 'A joyful noise', 'A great feast', 'A long prayer', 'b', 'The psalmist declared, "Make a joyful noise unto God, all ye lands" (Psalm 66:1).'),
('Psalms', 66, 'kids', 2, 'What did God do to the sea that the people walked through on dry ground?', 'He parted it', 'He turned it into dry land', 'He froze it solid', 'He drained it away', 'b', 'The psalmist recalled, "He turned the sea into dry land: they went through the flood on foot" (Psalm 66:6).'),
('Psalms', 66, 'kids', 3, 'What did the psalmist say God had not done — proving he heard prayer?', 'Removed his blessings', 'Turned away from him or withheld his mercy', 'Sent enemies against him', 'Forgotten his name', 'b', 'The psalmist said God had "not turned away my prayer, nor his mercy from me" (Psalm 66:20).'),
('Psalms', 66, 'teens', 1, 'What does the psalmist invite people to do in Psalm 66:5?', 'Enter the temple and worship', 'Come and see the works of God', 'Fast and pray for Israel', 'Offer their firstfruits to God', 'b', 'The psalmist called, "Come and see the works of God: he is terrible in his doing toward the children of men" (Psalm 66:5).'),
('Psalms', 66, 'teens', 2, 'What two extreme experiences does the psalmist say God brought his people through in Psalm 66:12?', 'Famine and plenty, war and peace', 'Fire and water, then into a wealthy place', 'The desert and the sea, the valley and the mountain', 'Captivity and freedom, hunger and feasting', 'b', 'The psalmist declared, "Thou hast caused men to ride over our heads; we went through fire and through water: but thou broughtest us out into a wealthy place" (Psalm 66:12).'),
('Psalms', 66, 'teens', 3, 'What specific offering does the psalmist vow to bring to God''s house in Psalm 66:13-15?', 'Grain and wine', 'Burnt offerings, rams, bullocks, and goats', 'Silver and gold', 'Firstfruits and tithes', 'b', 'The psalmist vowed to bring "burnt offerings... bullocks, with rams; I will offer bullocks with goats" (Psalm 66:13-15).'),
('Psalms', 66, 'teens', 4, 'What condition does the psalmist say would prevent God from hearing prayer in Psalm 66:18?', 'Not attending the temple', 'Regarding iniquity in the heart', 'Failing to fast', 'Not offering sacrifices', 'b', 'The psalmist said, "If I regard iniquity in my heart, the Lord will not hear me" (Psalm 66:18).'),
('Psalms', 66, 'teens', 5, 'What does Psalm 66:3 say that God''s enemies do because of his great power?', 'They flee in terror', 'They submit themselves to him', 'They are destroyed immediately', 'They call on him for mercy', 'b', 'The psalmist wrote, "Say unto God, How terrible art thou in thy works! through the greatness of thy power shall thine enemies submit themselves unto thee" (Psalm 66:3).'),
('Psalms', 66, 'adults', 1, 'What does "make a joyful noise" (Psalm 66:1) — the Hebrew rua — specifically connote beyond mere singing?', 'A soft and reverent tone', 'A loud, triumphant shout associated with battle victory and royal acclamation', 'A musical scale or melody', 'A priestly chant', 'b', 'Rua (Psalm 66:1) is a shout of triumph, the same word used for the battle cry and the acclamation of kings — it is joyful clamour before God.'),
('Psalms', 66, 'adults', 2, 'How does Psalm 66:6 allude to the Exodus and what does this say about God''s ongoing identity for Israel?', 'It is a vague reference to any past miracle', 'It recalls the parting of the Red Sea (Exodus 14), establishing that God''s saving acts define his identity for every generation', 'It refers to Joshua crossing the Jordan', 'It describes a future event', 'b', 'Psalm 66:6 recalls God turning the sea to dry land — clearly echoing Exodus 14 — reminding every generation that the Exodus God is still their God.'),
('Psalms', 66, 'adults', 3, 'What does "the eyes of God observe the nations" (Psalm 66:7) assert about divine governance?', 'God is passive and watches without acting', 'God''s omniscient watch over nations means he actively governs history and will not allow rebellion to go unchecked', 'God watches only Israel', 'The nations are unaware of God''s observation', 'b', 'Psalm 66:7 asserts divine sovereignty over world history: God''s watchful eyes over nations means he governs, not merely observes.'),
('Psalms', 66, 'adults', 4, 'What is the theological purpose of the trials described in Psalm 66:10-12 — the refining, burden, and fire and water?', 'God punishes his people for sin without purpose', 'God tests and refines his people as silver is refined — trials are instruments of purification and preparation for blessing', 'The trials are accidents of history', 'The people brought trials upon themselves only', 'b', 'Psalm 66:10 says God has "proved us... as silver is tried" — the fire and water of Psalm 66:12 are intentional purifying trials leading to a wealthy place.'),
('Psalms', 66, 'adults', 5, 'What is the distinction in Psalm 66:13-15 between vows made in distress and their fulfillment in prosperity?', 'The psalmist forgot his vows in prosperity', 'The psalmist faithfully fulfills in public worship what he promised in private crisis — integrity of covenant commitment', 'Vows made in distress are not binding', 'The offerings replace the verbal vows', 'b', 'The psalmist vowed offerings in distress (Psalm 66:14) and now brings them (Psalm 66:13, 15) — a model of vow-keeping integrity (cf. Ecclesiastes 5:4-5).'),
('Psalms', 66, 'adults', 6, 'What does "I regard iniquity in my heart" (Psalm 66:18) teach about the prerequisites for effective prayer?', 'Only priests can pray effectively', 'Cherished unconfessed sin creates a barrier between the worshipper and God''s hearing', 'Prayer is effective regardless of the heart''s state', 'God hears all prayers but not all are answered', 'b', 'Psalm 66:18 teaches that harboured sin (iniquity regarded in the heart) prevents God from hearing prayer — heart purity is prerequisite to answered prayer.'),
('Psalms', 66, 'adults', 7, 'What does the personal testimony section of Psalm 66:16-19 ("Come and hear, all ye that fear God") model for OT believers?', 'Private religion kept to oneself', 'Public declaration of God''s personal acts of salvation — the testimony as worship and witness', 'A priestly proclamation from the temple', 'A legal deposition before the assembly', 'b', 'Psalm 66:16-19 models the public testimony as an act of worship — "I will declare what he hath done for my soul" (Psalm 66:16) — personal faith shared communally.'),
('Psalms', 66, 'adults', 8, 'How does Psalm 66 transition between communal history (66:1-12) and personal testimony (66:13-20)?', 'The speaker changes from a choir to a king', 'The psalm moves from corporate salvation history to individual response and vow-fulfillment, integrating national and personal faith', 'The two sections are unrelated fragments', 'A liturgical rubric marks the division', 'b', 'Psalm 66 is a masterful integration of corporate history (66:1-12) with personal testimony (66:13-20), showing that Israel''s salvation story is also each believer''s story.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 67, 'kids', 1, 'What did the psalmist ask God to do to his face in Psalm 67?', 'Turn it away', 'Make it shine upon us', 'Show it in the heavens', 'Hide it in mercy', 'b', 'The psalmist prayed, "God be merciful unto us, and cause his face to shine upon us" (Psalm 67:1).'),
('Psalms', 67, 'kids', 2, 'What repeated phrase shows the psalmist''s desire for all people to praise God?', 'Praise him all the earth', 'Let the people praise thee, O God; let all the people praise thee', 'Shout for joy all nations', 'Bless the LORD all his works', 'b', 'The refrain "Let the people praise thee, O God; let all the people praise thee" appears in Psalm 67:3 and 67:5.'),
('Psalms', 67, 'kids', 3, 'What does Psalm 67 say God shall do to show he is their God?', 'Send fire from heaven', 'Bless them and make the earth yield her increase', 'Speak to them from a cloud', 'Give them a promised land', 'b', 'The psalmist wrote, "Then shall the earth yield her increase; and God, even our own God, shall bless us" (Psalm 67:6).'),
('Psalms', 67, 'teens', 1, 'What is the purpose stated in Psalm 67:2 for God blessing Israel?', 'That Israel would be the greatest nation', 'That God''s way may be known upon earth and his saving health among all nations', 'That other nations would fear Israel', 'That Israel would multiply greatly', 'b', 'The psalmist prayed for God''s blessing so "that thy way may be known upon earth, thy saving health among all nations" (Psalm 67:2).'),
('Psalms', 67, 'teens', 2, 'What reason is given for the nations to be glad in Psalm 67:4?', 'God gives them prosperity', 'God judges the people righteously and governs the nations upon earth', 'God delivers them from their enemies', 'God gives them wisdom and law', 'b', 'The psalmist said, "O let the nations be glad and sing for joy: for thou shalt judge the people righteously, and govern the nations upon earth" (Psalm 67:4).'),
('Psalms', 67, 'teens', 3, 'Psalm 67 is considered a "missionary psalm." What makes it missionary in character?', 'It commands Israel to go to other nations', 'It prays that God''s salvation and blessing of Israel will become known to and shared with all nations', 'It describes a mission journey', 'It lists nations that will be converted', 'b', 'Psalm 67 is missionary because it prays that Israel''s blessing will reveal God''s way to all nations (Psalm 67:2) — a centripetal mission theology.'),
('Psalms', 67, 'teens', 4, 'The opening of Psalm 67:1 echoes what famous OT blessing?', 'The Shema from Deuteronomy 6', 'The Aaronic blessing from Numbers 6:24-26', 'The blessing of Jacob in Genesis 49', 'The benediction at the end of Leviticus', 'b', 'Psalm 67:1 echoes the Aaronic blessing: "The LORD make his face shine upon thee, and be gracious unto thee" (Numbers 6:25).'),
('Psalms', 67, 'teens', 5, 'How many times does the refrain "let the people praise thee" appear in Psalm 67?', 'Once', 'Twice', 'Three times', 'Four times', 'b', 'The refrain "Let the people praise thee, O God; let all the people praise thee" appears twice — in Psalm 67:3 and 67:5.'),
('Psalms', 67, 'adults', 1, 'How does Psalm 67''s opening allusion to the Aaronic blessing (Numbers 6:24-26) connect Israel''s priestly vocation to missionary purpose?', 'Israel is to be a nation that keeps blessings to itself', 'Israel as a "kingdom of priests" (Exodus 19:6) receives God''s blessing in order to mediate it to all nations', 'The Aaronic blessing was only for the tribe of Levi', 'The psalm rejects the Aaronic blessing as insufficient', 'b', 'By echoing Numbers 6:24-26, Psalm 67 frames Israel''s blessing within its priestly calling (Exodus 19:6) — blessed to be a blessing to all nations (cf. Genesis 12:3).'),
('Psalms', 67, 'adults', 2, 'What does "thy saving health" (Psalm 67:2) — literally "thy salvation" (yeshuah) — anticipate in redemptive history?', 'The military victories of Israel''s kings', 'The universal proclamation of salvation through Yeshua (Jesus) to all nations', 'The physical healing of all nations', 'The agricultural prosperity described in verse 6', 'b', 'The Hebrew yeshuah (saving health/salvation, Psalm 67:2) shares a root with Yeshua (Jesus) — pointing forward to the universal salvation Christ brings to all nations.'),
('Psalms', 67, 'adults', 3, 'What is the structural role of the refrain in Psalm 67:3 and 67:5?', 'It marks liturgical pauses for the congregation to kneel', 'It creates a concentric structure framing the reasons for universal praise — God''s just rule (67:4) and his provision (67:6)', 'It was sung by a different choir', 'It divides the psalm into unrelated sections', 'b', 'The refrain in Psalm 67:3 and 67:5 frames the central verse (67:4) about God''s just governance of nations, creating a chiastic structure for the psalm.'),
('Psalms', 67, 'adults', 4, 'What two aspects of God''s governance are highlighted in Psalm 67:4 as reasons for the nations to rejoice?', 'His power and his wealth', 'Righteous judgment of peoples and just governing of nations', 'His mercy and his patience', 'His creation and his providence', 'b', 'Psalm 67:4 says the nations should rejoice because God "shalt judge the people righteously, and govern the nations upon earth" — just rule is cause for universal joy.'),
('Psalms', 67, 'adults', 5, 'How does the agricultural blessing of Psalm 67:6 function within the psalm''s theological argument?', 'It is merely a prayer for good harvests', 'It connects God''s material provision of Israel to the missionary goal — visible blessing testifies to God''s character before the nations', 'It replaces the need for the temple', 'It is a covenant condition for Israel''s obedience', 'b', 'The earth''s yield (Psalm 67:6) is not isolated — Israel''s visible blessing by God testifies to his character and draws nations to him (cf. Deuteronomy 28:1-10).'),
('Psalms', 67, 'adults', 6, 'What does "God, even our own God" (Psalm 67:6) emphasize in the context of a psalm addressed to all nations?', 'God belongs exclusively to Israel and not the nations', 'The universal God who blesses all nations is also the personal covenant God of Israel — particularity within universality', 'God has different identities for different peoples', 'The nations have their own gods and Israel has hers', 'b', 'The juxtaposition of "all nations" (Psalm 67:2) with "our own God" (Psalm 67:6) holds together God''s universal sovereignty and his particular covenant relationship with Israel.'),
('Psalms', 67, 'adults', 7, 'How does Psalm 67 anticipate the Great Commission (Matthew 28:19)?', 'It commands Israel to go to all nations with the Torah', 'It prays for all nations to know God''s salvation — the same missional goal as Christ''s command to make disciples of all nations', 'It predicts that Israel will rule all nations', 'It has no connection to the New Testament', 'b', 'Psalm 67''s prayer for all nations to know God''s saving way (Psalm 67:2) is the OT anticipation of the Great Commission — the same universal missional heart.'),
('Psalms', 67, 'adults', 8, 'What is the logical flow of Psalm 67''s theology: blessing → knowledge → praise → more blessing?', 'God blesses Israel, all nations see it, all nations praise God, and God blesses all the earth', 'God punishes nations, they repent, they praise, and God blesses them', 'Israel praises God, God blesses them, the nations learn from Israel, and God judges the nations', 'Nations praise God first, then he blesses them, then Israel sees his power', 'a', 'Psalm 67''s logic is: God blesses Israel (67:1) → his way known among nations (67:2) → nations praise (67:3-5) → earth yields increase and all are blessed (67:6-7).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 68, 'kids', 1, 'What does Psalm 68:1 say will happen to God''s enemies when God arises?', 'They will surrender', 'They will be scattered', 'They will be captured', 'They will flee to other lands', 'b', 'David wrote, "Let God arise, let his enemies be scattered: let them also that hate him flee before him" (Psalm 68:1).'),
('Psalms', 68, 'kids', 2, 'What does Psalm 68:5 call God in relation to those who have no father?', 'The provider of the fatherless', 'A father of the fatherless', 'The protector of the fatherless', 'The comforter of the fatherless', 'b', 'David declared that God is "A father of the fatherless, and a judge of the widows, is God in his holy habitation" (Psalm 68:5).'),
('Psalms', 68, 'kids', 3, 'What did Psalm 68:18 say God did on high — something Paul quotes in Ephesians 4:8?', 'He built a throne in heaven', 'He ascended on high and led captivity captive', 'He sent rain from heaven', 'He spoke from the clouds', 'b', 'David wrote, "Thou hast ascended on high, thou hast led captivity captive: thou hast received gifts for men" (Psalm 68:18).'),
('Psalms', 68, 'teens', 1, 'What does Psalm 68 say God does for the solitary and the prisoners?', 'He gives them strength to endure', 'He sets the solitary in families and brings out prisoners into prosperity', 'He sends angels to comfort them', 'He shortens their suffering', 'b', 'David wrote, "God setteth the solitary in families: he bringeth out those which are bound with chains" (Psalm 68:6).'),
('Psalms', 68, 'teens', 2, 'What natural phenomena accompanied God''s march through the wilderness in Psalm 68?', 'Fire and wind', 'The earth shook and the heavens dropped rain', 'Thunder and lightning', 'The mountains melted like wax', 'b', 'David recalled, "The earth shook, the heavens also dropped at the presence of God: even Sinai itself was moved at the presence of God" (Psalm 68:8).'),
('Psalms', 68, 'teens', 3, 'How does Psalm 68:11 describe those who spread the good news of God''s victory?', 'As mighty warriors', 'As a great company of those that published it', 'As singing priests', 'As prophets sent to the nations', 'b', 'David wrote, "The Lord gave the word: great was the company of those that published it" (Psalm 68:11).'),
('Psalms', 68, 'teens', 4, 'What mountain does Psalm 68:16 identify as the mountain God desires to dwell in?', 'Mount Sinai', 'Mount Zion', 'Mount Carmel', 'Mount Hermon', 'b', 'David wrote, "This is the hill which God desireth to dwell in; yea, the LORD will dwell in it for ever" (Psalm 68:16) — referring to Zion.'),
('Psalms', 68, 'teens', 5, 'What does Psalm 68:20 say about God and the issues of death?', 'Death is a punishment for the wicked only', 'Unto God the Lord belong the issues from death', 'God removes death from those who trust him', 'Death comes only to those who rebel against God', 'b', 'David declared, "Unto God the Lord belong the issues from death" (Psalm 68:20) — God controls the gates of death.'),
('Psalms', 68, 'adults', 1, 'How does Psalm 68:1 echo Numbers 10:35, and what is the theological significance of this echo?', 'Both describe the ark of the covenant in battle', 'Both use the priestly battle cry when the ark advanced, connecting Israel''s worship march to God''s warrior presence', 'Both are thanksgiving psalms for military victory', 'Both describe the return of the ark to Jerusalem', 'b', 'Psalm 68:1 directly quotes Numbers 10:35 — "Rise up, LORD, and let thine enemies be scattered" — the ancient ark-march formula, situating Israel''s worship in God''s warrior-presence.'),
('Psalms', 68, 'adults', 2, 'Paul quotes Psalm 68:18 in Ephesians 4:8, applying it to Christ''s ascension. What does "led captivity captive" mean in both the OT and NT contexts?', 'Both refer to taking prisoners of war as slaves', 'In the OT it describes God''s triumph over enemies; in the NT Paul applies it to Christ''s victory over sin, death, and spiritual powers at his ascension', 'The verse only applies to Pentecost', 'Paul misquotes the verse by changing "received" to "gave"', 'b', 'Psalm 68:18''s triumphal ascent (God leading captives) is applied by Paul (Ephesians 4:8) to Christ''s ascension, which conquered spiritual enemies and distributed gifts to the church.'),
('Psalms', 68, 'adults', 3, 'What does the description of God as "father of the fatherless, and a judge of the widows" (Psalm 68:5) reveal about Israel''s covenant ethics?', 'God only cares for Israel''s military strength', 'God''s character demands care for the most vulnerable — the fatherless and widow are special objects of his concern', 'Widows and orphans were excluded from worship', 'This is merely a poetic exaggeration', 'b', 'God as father of the fatherless and defender of widows (Psalm 68:5) grounds Israel''s social ethics in divine character — care for the vulnerable is a covenant obligation (cf. Deuteronomy 10:18).'),
('Psalms', 68, 'adults', 4, 'What is the significance of Mount Bashan''s envy of Mount Zion in Psalm 68:15-16?', 'Bashan was physically taller than Zion', 'High, imposing mountains are superseded by small Zion — God''s choice of the humble place over the impressive demonstrates his sovereign freedom', 'Bashan was Israel''s enemy territory', 'The psalm describes a literal geological event', 'b', 'The contrast between high Bashan and small Zion (Psalm 68:15-16) shows that God chooses the lowly — his dwelling is not determined by natural grandeur but by his sovereign will.'),
('Psalms', 68, 'adults', 5, 'What is the eschatological scope of Psalm 68:29-32, which anticipates kings bringing gifts to God?', 'It is limited to Solomon''s temple dedications', 'It anticipates the eschatological ingathering of nations to Zion — a Gentile submission to God''s kingship', 'It describes the tribute of conquered enemies', 'It refers to the return from Babylonian exile', 'b', 'Psalm 68:29-32 anticipates kings from Egypt and Ethiopia bringing gifts to God (cf. Isaiah 60) — an eschatological vision of universal Gentile submission to Israel''s God.'),
('Psalms', 68, 'adults', 6, 'How does Psalm 68''s procession theology relate to the physical movement of the ark of the covenant?', 'It is purely metaphorical and unrelated to the ark', 'The psalm likely accompanied the ark''s triumphal procession to Jerusalem, making God''s physical march with his people the occasion for cosmic theology', 'The ark is never mentioned in the psalm', 'The psalm was written centuries after the ark was lost', 'b', 'Psalm 68 is widely understood as a liturgical processional accompanying the ark — God''s physical march with Israel (68:7-8) becomes the lens for cosmic theology.'),
('Psalms', 68, 'adults', 7, 'What does the list of tribes in Psalm 68:27 (Benjamin, Judah, Zebulun, Naphtali) represent?', 'The four tribes that led Israel''s armies', 'A representative gathering of all Israel — north and south, small and great — united in worship', 'The tribes that accompanied the ark from the wilderness', 'The four cardinal points of Israel''s tribal arrangement', 'b', 'The four tribes (Psalm 68:27) represent all Israel — Benjamin and Judah from the south, Zebulun and Naphtali from the north — the whole nation united before God.'),
('Psalms', 68, 'adults', 8, 'What is the theological climax of Psalm 68, and where does it occur?', 'The call to praise in verse 1', 'The universal praise of all kingdoms and nations in verses 32-35, culminating in the declaration of God''s strength and power', 'The ascension of God in verse 18', 'The defeat of enemies in verse 21', 'b', 'Psalm 68 climaxes in a universal call for all kingdoms to sing to God (Psalm 68:32-35) — all the earth declaring his strength and power above all.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 69, 'kids', 1, 'What did the enemies give David to drink in Psalm 69?', 'Bitter water', 'Vinegar', 'Salt water', 'Poison', 'b', 'David wrote, "They gave me also gall for my meat; and in my thirst they gave me vinegar to drink" (Psalm 69:21).'),
('Psalms', 69, 'kids', 2, 'What did David say consumed him regarding God''s house?', 'A great love for its beauty', 'The zeal of thine house', 'A desire to serve as a priest', 'A longing to see God''s glory', 'b', 'David said, "The zeal of thine house hath eaten me up" (Psalm 69:9).'),
('Psalms', 69, 'kids', 3, 'To what was David sinking in the opening of Psalm 69?', 'Quicksand', 'Deep mire and deep waters', 'A dark pit', 'A flooded river', 'b', 'David cried, "I sink in deep mire, where there is no standing: I am come into deep waters, where the floods overflow me" (Psalm 69:2).'),
('Psalms', 69, 'teens', 1, 'What does Psalm 69:9 say about the reproaches of those who reproached God?', 'They were justly punished', 'They fell upon David', 'They were ignored by God', 'They strengthened David''s faith', 'b', 'David wrote, "The reproaches of them that reproached thee are fallen upon me" (Psalm 69:9).'),
('Psalms', 69, 'teens', 2, 'What was David''s condition that made him a stranger to his family in Psalm 69:8?', 'His poverty', 'His zeal for God made him an alien to his brethren and a stranger to his mother''s children', 'His long absence on a journey', 'His leper disease', 'b', 'David wrote, "I am become a stranger unto my brethren, and an alien unto my mother''s children" because of his zeal for God (Psalm 69:8-9).'),
('Psalms', 69, 'teens', 3, 'What did David say his enemies hated him without a cause for in Psalm 69:4?', 'For his wealth', 'They that hate me without a cause are more than the hairs of mine head', 'For his royal power', 'For his righteous judgments', 'b', 'David lamented, "They that hate me without a cause are more than the hairs of mine head" (Psalm 69:4).'),
('Psalms', 69, 'teens', 4, 'How does Psalm 69:21 connect to the crucifixion of Jesus?', 'Jesus quoted this verse on the cross', 'The vinegar given to Jesus at the cross (Matthew 27:48; John 19:29) fulfills this verse', 'Jesus prayed this psalm in Gethsemane', 'John cites it as fulfilled at the Last Supper', 'b', 'Psalm 69:21 — "in my thirst they gave me vinegar to drink" — is fulfilled in John 19:29 when soldiers offered Jesus vinegar (sour wine) at the crucifixion.'),
('Psalms', 69, 'teens', 5, 'What does the psalmist say God will do for the humble and the poor in the closing section of Psalm 69:32-33?', 'Give them wealth and honour', 'The humble shall see and be glad; the LORD heareth the poor', 'Deliver them from all enemies', 'Restore them to their families', 'b', 'David declared, "The humble shall see this, and be glad... For the LORD heareth the poor, and despiseth not his prisoners" (Psalm 69:32-33).'),
('Psalms', 69, 'adults', 1, 'How many times is Psalm 69 quoted or alluded to in the New Testament, making it one of the most-cited OT texts?', 'Twice', 'About three times', 'At least seven times', 'Once', 'c', 'Psalm 69 is one of the most-quoted psalms in the NT — cited at least seven times including Romans 11:9-10, John 2:17, John 15:25, Matthew 27:48, Acts 1:20, and Romans 15:3.'),
('Psalms', 69, 'adults', 2, 'John 2:17 quotes Psalm 69:9 in reference to Jesus cleansing the temple. What theological connection does John draw?', 'Jesus was fulfilling a legal obligation', 'Jesus'' zeal for God''s house consuming him identifies him as the messianic sufferer of Psalm 69 who bears the cost of God''s honour', 'Jesus was angry at the merchants personally', 'John uses the verse to show Jesus loved the temple building', 'b', 'John 2:17 applies Psalm 69:9 to Jesus — his consuming zeal for God''s house identifies him as the messianic servant who bears divine reproach (John 2:17; cf. Romans 15:3).'),
('Psalms', 69, 'adults', 3, 'How does "they hated me without a cause" (Psalm 69:4) function in John 15:25?', 'Jesus quotes it as a legal precedent', 'Jesus applies it to himself — the world''s hatred of him without cause fulfills Scripture, confirming his messianic identity', 'John uses it as a general proverb', 'It is used to defend the disciples'' innocence', 'b', 'Jesus directly applies Psalm 69:4 in John 15:25 — the world''s baseless hatred of him "fulfilleth the word that is written in their law" — messianic fulfillment.'),
('Psalms', 69, 'adults', 4, 'What is the imprecatory nature of Psalm 69:22-28, and how has it been applied in the NT?', 'It is a prayer for enemies'' salvation', 'It calls God''s judgment on enemies; Acts 1:20 applies verse 25 to Judas Iscariot''s fate', 'It is purely historical and never applied in the NT', 'It predicts the destruction of Jerusalem in 70 AD', 'b', 'Psalm 69:25 ("Let their habitation be desolate") is quoted in Acts 1:20 as fulfilled in Judas Iscariot, whose betrayal brought upon him the judgment prophesied here.'),
('Psalms', 69, 'adults', 5, 'What does the opening water imagery (sinking in mire, floods, deep waters, Psalm 69:1-3, 14-15) represent as a metaphorical system?', 'Literal drowning David experienced', 'Chaotic, overwhelming suffering threatening to extinguish life — the deep waters symbolize mortal crisis beyond human rescue', 'The waters of the Red Sea', 'A spiritual purification ritual', 'b', 'The deep waters and mire of Psalm 69:1-3, 14-15 are ancient Near Eastern chaos imagery — overwhelming, life-threatening suffering from which only God can save.'),
('Psalms', 69, 'adults', 6, 'What does "blot them out of the book of the living" (Psalm 69:28) imply about Israel''s theology of divine records?', 'It is merely a poetic wish', 'It implies a heavenly register of the living from which the condemned are erased — anticipating the book of life in Revelation', 'It refers to the genealogical records of Israel', 'It is a priestly curse formula', 'b', 'Psalm 69:28''s book of the living anticipates the NT book of life (Revelation 3:5; 20:15) — a divine register of those in covenant relationship with God.'),
('Psalms', 69, 'adults', 7, 'How does Psalm 69:30-31 theologically reorder Israel''s sacrificial system?', 'It abolishes animal sacrifice entirely', 'It subordinates animal sacrifice to the praise of a thankful heart — God is more pleased with grateful song than burnt offerings', 'It argues that sacrifices are more important than praise', 'It restricts praise to the Levitical singers', 'b', 'Psalm 69:30-31 declares that praising God with a song pleases him more than an ox or bullock — an OT anticipation of the prophetic critique of empty ritual (cf. Psalm 51:16-17; Hosea 6:6).'),
('Psalms', 69, 'adults', 8, 'What does Psalm 69''s structure (lament → imprecation → praise → eschatological hope) model for NT believers facing unjust suffering?', 'That imprecatory prayer is forbidden in the NT', 'That honest lament can coexist with praise, and God''s ultimate justice transforms present suffering into eschatological hope', 'That believers should suppress their complaints', 'That suffering is always the result of personal sin', 'b', 'Psalm 69 models the journey from raw lament (69:1-4) through honest prayer (69:5-28) to confident praise (69:30-36) — a model for NT believers facing unjust suffering (cf. Romans 8:18-25).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 70, 'kids', 1, 'What did David urgently ask God to do in the very first verse of Psalm 70?', 'Give him victory in battle', 'Make haste to deliver him', 'Send his angels to protect him', 'Forgive all his sins', 'b', 'David prayed, "Make haste, O God, to deliver me; make haste to help me, O LORD" (Psalm 70:1).'),
('Psalms', 70, 'kids', 2, 'What did David ask God to do to those who sought his life?', 'Forgive them', 'Let them be ashamed and confounded', 'Send them away to other lands', 'Give them a chance to repent', 'b', 'David prayed, "Let them be ashamed and confounded that seek after my soul" (Psalm 70:2).'),
('Psalms', 70, 'kids', 3, 'What did David call himself — showing his need for God?', 'A mighty warrior', 'Poor and needy', 'A humble servant', 'A faithful king', 'b', 'David concluded, "But I am poor and needy: make haste unto me, O God" (Psalm 70:5).'),
('Psalms', 70, 'teens', 1, 'What does David say the seekers of God should continually say?', 'Bless the LORD all ye peoples', 'Let God be magnified', 'Praise the LORD for he is good', 'Holy is the LORD God Almighty', 'b', 'David said, "Let all those that seek thee rejoice and be glad in thee: and let such as love thy salvation say continually, Let God be magnified" (Psalm 70:4).'),
('Psalms', 70, 'teens', 2, 'What does David pray about those who say "Aha, aha!" (mocking him)?', 'That they will be converted', 'That they will be turned backward and put to shame', 'That they will be silenced', 'That they will be defeated in battle', 'b', 'David prayed, "Let them be turned backward, and put to confusion, that desire my hurt... that say, Aha, aha" (Psalm 70:2-3).'),
('Psalms', 70, 'teens', 3, 'Psalm 70 is almost identical to which earlier psalm?', 'Psalm 22:19-21', 'Psalm 40:13-17', 'Psalm 51:1-5', 'Psalm 35:4-8', 'b', 'Psalm 70 is nearly identical to Psalm 40:13-17 — both are urgent prayers for deliverance, with Psalm 70 being an independent liturgical use of that section.'),
('Psalms', 70, 'teens', 4, 'What does the brevity of Psalm 70 (only 5 verses) communicate about the nature of urgent prayer?', 'Short prayers are less effective', 'Genuine crisis prayer can be intense and brief — urgency strips prayer to its essentials', 'David was too tired to write more', 'Only long prayers receive answers', 'b', 'Psalm 70''s five-verse brevity captures the essence of crisis prayer — urgency and desperate need strip the prayer down to its bare essentials before God.'),
('Psalms', 70, 'teens', 5, 'What superscription or title does Psalm 70 carry that indicates its liturgical function?', 'A prayer of the afflicted', 'A psalm of David to bring to remembrance', 'A song of degrees', 'A maskil for understanding', 'b', 'Psalm 70 is headed "A Psalm of David, to bring to remembrance" — suggesting it was used as a memorial/petition in Israel''s liturgy.'),
('Psalms', 70, 'adults', 1, 'What does "to bring to remembrance" in Psalm 70''s superscription suggest about its liturgical use?', 'David wanted future generations to memorize it', 'It was used in the context of the "memorial offering" (azkarah) — a ritual bringing the worshipper''s need before God''s attention', 'It was a royal decree', 'It was placed in the temple archives', 'b', 'The title "to bring to remembrance" (Psalm 70 superscription) likely connects to the azkarah (memorial portion of the grain offering) — a liturgical bringing of oneself before God.'),
('Psalms', 70, 'adults', 2, 'How does Psalm 70''s repetition of "make haste" (verses 1 and 5) function rhetorically?', 'It shows David''s impatience with God', 'The double urgency frames the entire psalm — every word is under the pressure of desperate need', 'It is a liturgical chorus', 'It balances the two stanzas', 'b', 'The twin urgency of "make haste" in Psalm 70:1 and 70:5 creates an envelope of crisis — the whole psalm breathes urgency and radical dependence on God.'),
('Psalms', 70, 'adults', 3, 'What does the contrast between the fate of enemies (ashamed, confounded, 70:2-3) and the righteous (glad, rejoicing, 70:4) reveal about OT theodicy?', 'Righteous and wicked have identical destinies', 'God''s justice guarantees opposite outcomes — the wicked''s shame is the necessary counterpart to the righteous''s joy', 'Righteousness guarantees immediate reward', 'The wicked are not judged until death', 'b', 'Psalm 70''s sharp contrast — enemies confounded (70:2-3) vs. seekers rejoicing (70:4) — reflects OT theodicy: God''s justice ensures that righteousness and wickedness lead to opposite ends.'),
('Psalms', 70, 'adults', 4, 'What is the theological significance of David''s self-description as "poor and needy" (Psalm 70:5) for a king?', 'David was literally impoverished at this time', 'It expresses radical spiritual poverty — total dependence on God regardless of earthly status, the posture of the "anawim" (humble poor)', 'It was a rhetorical device to gain sympathy', 'It describes David''s early pre-royal life', 'b', 'David calling himself poor and needy (Psalm 70:5) despite being king reflects the anawim spirituality — the humble poor who depend entirely on God (cf. Matthew 5:3, "poor in spirit").'),
('Psalms', 70, 'adults', 5, 'When Psalm 70 is compared to Psalm 40:13-17, what does the independent use of this prayer section reveal?', 'One version is a scribal error', 'Individual psalm sections circulated independently and were reused in different liturgical contexts — scripture is organically living', 'Psalm 70 corrects an error in Psalm 40', 'David wrote Psalm 40 first and regretted it', 'b', 'The existence of Psalm 70 as a standalone version of Psalm 40:13-17 shows that psalm sections were excerpted and reused liturgically — Israel''s prayer treasury was fluid and living.'),
('Psalms', 70, 'adults', 6, 'How does "let God be magnified" (Psalm 70:4) function as a statement of priority within urgent crisis prayer?', 'It delays God''s help by praising first', 'Even in desperate crisis, David''s ultimate concern is God''s magnification — the worshipper''s need is subordinated to God''s glory', 'It is a standard liturgical formula', 'It means David wants God to appear visibly', 'b', 'David''s cry "let God be magnified" (Psalm 70:4) within an urgent lament reveals that even crisis prayer is ultimately theocentric — God''s glory is the supreme concern.'),
('Psalms', 70, 'adults', 7, 'What does the use of "LORD" (YHWH) in Psalm 70:1 and "God" (Elohim) in Psalm 70:1 and 5 reveal about the psalm''s divine address?', 'David is uncertain which name to use', 'Both the personal covenant name (YHWH) and the generic divine name (Elohim) are used, appealing to God in both his covenant relationship and universal power', 'The names are interchangeable with no significance', 'YHWH is used for praise and Elohim for petition', 'b', 'Psalm 70 addresses both YHWH (covenant name, 70:1) and Elohim (universal name, 70:1, 5), appealing to both God''s personal covenant faithfulness and his omnipotent power.'),
('Psalms', 70, 'adults', 8, 'How does Psalm 70''s raw urgency contribute to the Psalter''s honest theology of prayer?', 'It models polished, formal prayer', 'It validates desperate, unadorned cries to God — the Psalter permits and models raw urgency as legitimate prayer', 'It shows that only emotional prayers are answered', 'It warns against praying too urgently', 'b', 'Psalm 70''s unadorned urgency contributes to the Psalter''s honest prayer theology — it legitimises stripped-down crisis prayer as fully valid before God (cf. Romans 8:26).');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 71, 'kids', 1, 'What did the psalmist ask God not to do in his old age in Psalm 71?', 'Let him grow weak', 'Cast him off in the time of old age', 'Forget his prayers', 'Leave him without children', 'b', 'The psalmist prayed, "Cast me not off in the time of old age; forsake me not when my strength faileth" (Psalm 71:9).'),
('Psalms', 71, 'kids', 2, 'What did the psalmist say he had leaned on since his birth?', 'His family''s wisdom', 'God who took him out of his mother''s womb', 'The strength of his own body', 'The teachings of his people', 'b', 'The psalmist said, "By thee have I been holden up from the womb: thou art he that took me out of my mother''s bowels" (Psalm 71:6).'),
('Psalms', 71, 'kids', 3, 'What did the psalmist say he would always hope in and praise God more and more?', 'God''s provision of food', 'The righteousness of God', 'God''s mercy and strength', 'The laws of God', 'b', 'The psalmist declared, "But I will hope continually, and will yet praise thee more and more" (Psalm 71:14).'),
('Psalms', 71, 'teens', 1, 'What did the psalmist''s enemies say when they plotted against him in Psalm 71:11?', 'God has given him to us', 'God hath forsaken him: persecute and take him; for there is none to deliver him', 'He has no friends to help him', 'His God will not hear his prayer', 'b', 'The psalmist''s enemies said, "God hath forsaken him: persecute and take him; for there is none to deliver him" (Psalm 71:11).'),
('Psalms', 71, 'teens', 2, 'What does the psalmist say he will shew to this generation and everyone to come?', 'The law of Moses', 'God''s strength and righteous acts', 'The history of Israel', 'The words of the prophets', 'b', 'The psalmist declared, "I will shew thy strength unto this generation, and thy power to every one that is to come" (Psalm 71:18).'),
('Psalms', 71, 'teens', 3, 'What musical instrument does the psalmist mention praising God with in Psalm 71?', 'The trumpet', 'The psaltery and harp', 'The flute and drum', 'The cymbals', 'b', 'The psalmist declared, "I will also praise thee with the psaltery, even thy truth, O my God: unto thee will I sing with the harp" (Psalm 71:22).'),
('Psalms', 71, 'teens', 4, 'What does the psalmist ask God to do after showing him troubles and adversities in Psalm 71?', 'Give him peace at last', 'Quicken him again and bring him up again from the depths of the earth', 'Give him rest in death', 'Send him a young successor', 'b', 'The psalmist prayed, "Thou, which hast shewed me great and sore troubles, shalt quicken me again, and shalt bring me up again from the depths of the earth" (Psalm 71:20).'),
('Psalms', 71, 'teens', 5, 'How does the psalmist describe God as his refuge from his youth in Psalm 71:5?', 'As his daily bread and water', 'As his hope and his trust from his youth', 'As the guide of all his ways', 'As the teacher of his people', 'b', 'The psalmist said, "For thou art my hope, O Lord GOD: thou art my trust from my youth" (Psalm 71:5).'),
('Psalms', 71, 'adults', 1, 'What is the likely setting of Psalm 71 and what makes it distinctive among the Psalms?', 'A young warrior going into battle', 'It is the prayer of an elderly believer — the only psalm explicitly voiced from the perspective of old age and lifelong faith', 'A king celebrating his coronation', 'A priest performing his annual duties', 'b', 'Psalm 71 is unique as the prayer of an aged person (Psalm 71:9, 18) — a lifelong believer reviewing God''s faithfulness from birth to old age.'),
('Psalms', 71, 'adults', 2, 'What does the psalmist''s phrase "thou art my strong refuge" (Psalm 71:7) — using the Hebrew "mahseh" — convey about his theology?', 'God is physically protective like a wall', 'Mahseh (refuge/shelter) describes God as a place of total security — the aged believer''s whole life has been spent under divine shelter', 'God rescued the psalmist from a specific battle', 'God is the refuge only in times of crisis', 'b', 'Mahseh (Psalm 71:7) is a rich refuge word — not just emergency protection but a lifelong dwelling in God''s sheltering care from womb to old age.'),
('Psalms', 71, 'adults', 3, 'How does Psalm 71''s interlacing of petition and praise (e.g., 71:1-4 petition, 71:5-8 praise, 71:9-13 petition) model the rhythm of mature prayer?', 'It shows that the psalmist forgot his train of thought', 'It models prayer as a living dialogue where trust and need alternate — praise does not wait until deliverance but interrupts lament', 'The sections were originally separate prayers', 'Petition and praise are kept strictly separate', 'b', 'Psalm 71''s interweaving of petition and praise models mature prayer — praise interrupts lament (71:5-8) because faith does not wait for deliverance to worship God.'),
('Psalms', 71, 'adults', 4, 'What does "I will go in the strength of the Lord GOD" (Psalm 71:16) declare about the aged believer''s source of ongoing vitality?', 'Physical strength is restored to the aged', 'In the absence of youthful strength, God''s strength becomes the sole source of the aged believer''s forward movement', 'The psalmist is beginning a military campaign', 'God gives the aged special supernatural ability', 'b', 'Psalm 71:16''s "I will go in the strength of the Lord GOD" is a declaration of radical dependence — the aged believer''s vitality comes entirely from God, not from self.'),
('Psalms', 71, 'adults', 5, 'What does the psalmist''s request in Psalm 71:18 — "forsake me not...until I have shewed thy strength unto this generation" — reveal about his understanding of his life''s purpose in old age?', 'Old age has no remaining purpose', 'The aged believer''s final purpose is testimony — to pass the knowledge of God''s power to the next generation', 'The psalmist fears death before completing temple service', 'God abandons the elderly when their strength fails', 'b', 'Psalm 71:18''s request to live until he can testify to the next generation reveals that the aged believer''s final vocation is intergenerational witness — faith passed to the next generation.'),
('Psalms', 71, 'adults', 6, 'How does the psalmist''s reference to being held from the womb (71:6) relate to his trust in God in old age?', 'It is a nostalgic memory', 'It creates a theological arc: if God was faithful from birth, he will be faithful in old age — the whole life as evidence for continued trust', 'Birth and old age are unrelated in the psalm', 'It refers to a miraculous birth like Isaac or Samuel', 'b', 'Psalm 71''s womb-to-old-age arc (71:6, 9, 18) builds a cumulative argument: God''s faithfulness across an entire life is the basis for trust in life''s final chapter.'),
('Psalms', 71, 'adults', 7, 'What is the significance of the psalmist''s vow to praise God with "lips that rejoice" (Psalm 71:23) when God restores him?', 'Praise is contingent on restoration', 'The lips that cried in lament will become the lips of praise — suffering and praise are part of one continuous testimony', 'Praise is only appropriate after complete victory', 'The psalmist had previously been silenced', 'b', 'Psalm 71:23''s rejoicing lips complete the journey from the crying soul of 71:2-3 — the same mouth that begged becomes the mouth that praises, unifying lament and doxology.'),
('Psalms', 71, 'adults', 8, 'How does Psalm 71 relate to the broader wisdom tradition''s teaching on the value of old age?', 'Old age is seen as a burden without spiritual value', 'It affirms the wisdom tradition''s view (Proverbs 16:31; 20:29) that old age can be a crown of lifelong faithfulness — a platform for testimony', 'The psalm is pessimistic about aging', 'Psalm 71 contradicts Proverbs on old age', 'b', 'Psalm 71 aligns with wisdom tradition (Proverbs 16:31 — "hoary head is a crown of glory") by presenting old age as the culmination of faithful life and a platform for testimony.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Psalms', 72, 'kids', 1, 'How far will the king''s dominion reach according to Psalm 72?', 'Only over Israel', 'From sea to sea and to the ends of the earth', 'Over all the mountains', 'From the north to the south only', 'b', 'The psalmist prayed, "He shall have dominion also from sea to sea, and from the river unto the ends of the earth" (Psalm 72:8).'),
('Psalms', 72, 'kids', 2, 'What does the psalmist say the king will do for the poor and needy?', 'Give them more work', 'Save the children of the needy and break in pieces the oppressor', 'Build them bigger cities', 'Teach them to be strong', 'b', 'The psalmist prayed, "He shall save the children of the needy, and shall break in pieces the oppressor" (Psalm 72:4).'),
('Psalms', 72, 'kids', 3, 'What is said about the king''s name in Psalm 72?', 'It shall be feared by all nations', 'His name shall endure for ever', 'It shall be written in the heavens', 'All kings shall know his name', 'b', 'The psalmist declared, "His name shall endure for ever: his name shall be continued as long as the sun" (Psalm 72:17).'),
('Psalms', 72, 'teens', 1, 'What two things does the king judge righteously in Psalm 72?', 'The rich and the powerful', 'The poor and the children of the needy', 'The priests and the prophets', 'The young and the old', 'b', 'The psalmist prayed that the king would "judge thy people with righteousness, and thy poor with judgment" (Psalm 72:2) and deliver the needy.'),
('Psalms', 72, 'teens', 2, 'What natural image illustrates the king''s refreshing rule over the people in Psalm 72:6?', 'A mighty wind that cools the land', 'He shall come down like rain upon the mown grass', 'A river of water in a dry land', 'A spring that never runs dry', 'b', 'The psalmist said, "He shall come down like rain upon the mown grass: as showers that water the earth" (Psalm 72:6).'),
('Psalms', 72, 'teens', 3, 'Who does Psalm 72 say shall bow before the king — specifically mentioning nations from the south?', 'The kings of the north only', 'The kings of Sheba and Seba shall offer gifts, all kings shall fall down before him', 'The nations conquered in battle', 'The people of Egypt and Babylon', 'b', 'The psalmist prayed, "The kings of Sheba and Seba shall offer gifts... all kings shall fall down before him: all nations shall serve him" (Psalm 72:10-11).'),
('Psalms', 72, 'teens', 4, 'What phrase closes Book II of the Psalms (Psalms 42-72) at the end of Psalm 72?', 'The LORD is my shepherd', 'The prayers of David the son of Jesse are ended', 'Let all the earth be filled with his glory', 'Praise ye the LORD for ever and ever', 'b', 'Psalm 72:20 reads, "The prayers of David the son of Jesse are ended" — the editorial colophon closing Book II of the Psalter.'),
('Psalms', 72, 'teens', 5, 'What does the psalmist say the king will do to the man in need who has no helper in Psalm 72:12?', 'Give him a judge to plead his case', 'Deliver him; he shall spare the poor and needy', 'Send him to the priests for help', 'Give him a field to work', 'b', 'The psalmist prayed, "He shall deliver the needy when he crieth; the poor also, and him that hath no helper" (Psalm 72:12).'),
('Psalms', 72, 'adults', 1, 'What is the dual horizon of Psalm 72 — which two kings does it simultaneously address?', 'David and his son Absalom', 'Solomon historically and the Messiah eschatologically — it is both a royal coronation prayer and a Messianic prophecy', 'David and Moses', 'Solomon and Hezekiah', 'b', 'Psalm 72 is simultaneously a prayer for Solomon at his coronation (its historical horizon) and a Messianic prophecy (its eschatological horizon) — no earthly king fully fulfills its vision.'),
('Psalms', 72, 'adults', 2, 'How does "he shall have dominion from sea to sea" (Psalm 72:8) connect to the Abrahamic covenant and its land promises?', 'It refers to Israel''s conquest of Canaan', 'It expands the land promise beyond Canaan to universal sovereignty — the king is the heir of all God''s covenant promises to Abraham', 'It describes the borders of Solomon''s kingdom', 'It is merely poetic hyperbole', 'b', 'Psalm 72:8''s universal dominion echoes the Abrahamic promise (Genesis 22:17-18) that Abraham''s seed would possess the gates of enemies — the king is the covenant heir.'),
('Psalms', 72, 'adults', 3, 'What does the abundance-of-grain image (Psalm 72:16 — "handful of corn on top of mountains") convey about the ideal king''s reign?', 'Israel will become an agricultural superpower', 'Messianic rule brings abundant, impossible fruitfulness — even barren mountaintops overflow with grain, reversing the curse', 'The king will be known for farming innovations', 'The mountains will be terraced for agriculture', 'b', 'Grain on mountain tops (Psalm 72:16) is a hyperbole of impossible abundance — Messianic rule reverses the curse and creates superabundant shalom (cf. Amos 9:13).'),
('Psalms', 72, 'adults', 4, 'How does Paul connect the universal blessing through the king''s name (Psalm 72:17 — "all nations shall be blessed in him") to the Abrahamic covenant in Galatians 3?', 'Paul does not connect these texts', 'Psalm 72:17 echoes Genesis 12:3 ("all families of the earth shall be blessed") — the Messianic king is the Seed of Abraham through whom all nations are blessed', 'The blessing is limited to nations that accept the Torah', 'The blessing refers to material prosperity only', 'b', 'Psalm 72:17''s "all nations shall be blessed in him" directly echoes Genesis 12:3 — the Messianic king is identified as the Abrahamic Seed through whom universal blessing comes (cf. Galatians 3:16).'),
('Psalms', 72, 'adults', 5, 'What is the ethical centre of Psalm 72''s vision of ideal kingship?', 'Military conquest and territorial expansion', 'Justice for the poor, needy, and oppressed — the king''s greatness is measured by his care for the vulnerable', 'Wisdom and learning above all virtues', 'Wealth and international tribute', 'b', 'The ethical centre of Psalm 72 is justice for the poor and oppressed (72:2, 4, 12-14) — the ideal king''s greatness is measured not by conquest but by how he protects the vulnerable.'),
('Psalms', 72, 'adults', 6, 'What does "he shall live" (Psalm 72:15) in the context of the psalm''s universalism suggest about the Messianic king''s life?', 'The king will simply have a long reign', 'It anticipates the eternal life of the Messianic king whose reign has no end — fulfilled in Christ''s resurrection', 'It is a prayer for Solomon''s health', 'It means the king will survive his enemies', 'b', 'Psalm 72:15''s "he shall live" within the context of eternal dominion (72:5, 17) points beyond any mortal king to the Messiah whose life and reign are eternal.'),
('Psalms', 72, 'adults', 7, 'What is the doxological function of Psalm 72:18-19 within the Psalter?', 'It concludes only Psalm 72', 'It is the closing doxology of Book II (Psalms 42-72), a liturgical benediction praising God whose glory fills the whole earth', 'It introduces Book III', 'It is a separate psalm misplaced here', 'b', 'Psalm 72:18-19 is the closing doxology of Book II of the Psalter (Psalms 42-72), blessing God and praying for his glory to fill all the earth.'),
('Psalms', 72, 'adults', 8, 'How does the image of the king defending the poor (Psalm 72:12-14) — "their blood shall be precious in his sight" — anticipate Christ''s redemptive work?', 'It is limited to economic welfare programs', 'The king who redeems the weak from oppression and counts their blood precious foreshadows Christ who redeems at the cost of his own precious blood', 'It describes Solomon''s judicial reforms', 'It is a military metaphor for protecting citizens', 'b', 'The king''s redemption of the needy with precious blood (Psalm 72:14) foreshadows Christ whose own blood (1 Peter 1:19) is the price of redemption for the weak and helpless.');
